import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS attack!')</script>";

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Printing the sanitized output to an HTML page
        try {
            PrintWriter out = new PrintWriter("output.html");
            out.println("<html><body>");
            out.println("Hello, " + sanitizedInput);
            out.println("</body></html>");
            out.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
